import { 立菩薩身 } from './lipusa.js';
import { 前臂 } from './pusa.js';
import { 手勢, 指寬 } from '../bujian/zhi.js';
import { 運筆 } from '../bi.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 月光菩薩 = (bi) => 立菩薩身(bi, {
    臂(bi, 筆) {
        const { M, C, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        // 尊右臂（觀者左）：屈肘上舉執蓮莖，莖上小蓮承月輪（素月雙環）
        衣(() => {
            M(-12.3, 34.2);
            C(-12.6, 30.0, -12.9, 25.4, -13.1, 20.9);
            S();
            M(-13.05, 34.15);
            C(-13.35, 30.0, -13.65, 25.4, -13.85, 20.9);
            S();
            M(-11.6, 20.9);
            Qk(-12.3, 19.4, -13.1, 19.0);
            S();
            M(-15.3, 20.8);
            Qk(-14.8, 19.5, -14.05, 19.05);
            S();
            M(-13.1, 19.0);
            Qk(-13.6, 18.8, -14.05, 19.05);
            S();
        });
        // 素月：雙環無芒（與日輪之焰芒相辨）
        {
            const 運 = 運筆(bi);
            運.衣(() => { bi.A(-13.5, 15.4, 2.5 * 0.75, 0, 7); });
            運.細(() => { bi.A(-13.5, 15.4, 2.2 * 0.75, 0, 7); });
        }
        骨(() => 陽(() => {
            M(-13.4, 28.6);
            C(-14.5, 30.8, -15.0, 33.6, -14.9, 36.4);
            S();
            M(-10.9, 32.4);
            C(-11.2, 34.0, -11.4, 35.4, -11.4, 36.6);
            S();
        }));
        骨(() => 陽(() => 前臂(bi, 筆, [-14.6, 37.4], [-12.9, 36.9], { 寬根: 2.4, 寬梢: 1.9, 弓: 0.2, 蔽: false })));
        側拳(bi, -12.7, 35.4, Math.PI / 2 - 0.15, 1.05);
        // 尊左臂（觀者右）：自然垂於體側
        骨(() => 陰(() => {
            M(13.4, 28.6);
            C(14.5, 32.6, 15.0, 38.5, 14.8, 45.5);
            S();
            M(10.9, 32.4);
            C(11.4, 36.5, 11.7, 41.0, 11.8, 45.5);
            S();
            M(14.8, 45.5);
            C(14.6, 50.5, 14.2, 55.5, 13.8, 60.0);
            S();
            M(11.8, 45.5);
            C(11.9, 50.0, 12.1, 54.5, 12.3, 58.6);
            S();
        }));
        {
            const s = 手勢(bi, 13.1, 63.2, 0.98, -1);
            s.衣(() => {
                s.M(-1.35, -2.9);
                s.Qk(-1.7, -1.2, -1.5, 0.4);
                s.S();
                s.M(1.05, -2.85);
                s.Qk(1.45, -1.4, 1.3, 0.1);
                s.S();
                for (const [i, 根a] of [-0.95, -0.3, 0.35, 0.95].entries()) {
                    const 鏈 = s.指(根a, 0.2, Math.PI / 2 - 0.06 + i * 0.05, [1.5 - Math.abs(i - 1.4) * 0.16, 1.1 - Math.abs(i - 1.4) * 0.12], [0, 0.22]);
                    s.畫(鏈, 指寬.根, 指寬.梢, { 紋: true });
                }
                const 拇 = s.指(-1.5, -0.6, Math.PI / 2 + 0.55, [1.25, 0.95], [0, -0.2]);
                s.畫(拇, 指寬.拇根, 指寬.拇梢, { 紋: true });
            });
        }
        // 嚴
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        臂釧(bi, -1, 12.0, 14.3, 31.8);
        細(() => {
            腕釧(bi, [[14.4, 59.4, 13.5, 59.9, 12.6, 59.5], [14.3, 60.4, 13.4, 60.9, 12.5, 60.5]], [13.4, 60.4]);
            腕釧(bi, [[-11.6, 37.9, -12.6, 38.4, -13.6, 38.0], [-11.5, 38.9, -12.5, 39.4, -13.5, 39.0]], [-12.5, 38.9]);
        });
    },
});
